const clamp=(t,n,e)=>Math.max(n,Math.min(t,e));function precisionRound(t,n=1){n=Math.pow(10,n);return Math.round(t*n)/n}function getDecimalPrecision(t){if(Math.abs(t)<1){const e=t.toExponential().split("e-");var n=e[0].split(".")[1];return(n?n.length:0)+parseInt(e[1],10)}n=t.toString().split(".")[1];return n?n.length:0}function roundValueToStep(t,n,e){const r=Math.round((t-e)/n)*n+e;return Number(r.toFixed(getDecimalPrecision(n)))}function decimatedClamp(t,n,e,r){if(null==r||r<=0)return clamp(t,n,e);t=roundValueToStep(t,r,n);return clamp(t,n,e)}function rescale(t,n,e,r={}){return decimatedClamp((t-n[0])/(n[1]-n[0])*(e[1]-e[0])+e[0],e[0],e[1],r.step)}export{clamp,precisionRound,rescale};